//! Runtime mirror of `Gnosis.PackingStrideGeometry` for visual hot paths.
//!
//! The Lean side certifies the stride-admissibility surface for the E8 exponent
//! lanes and the Leech kissing carrier. This module keeps distributed
//! inference aligned with the same finite lane schedule used by gnosis-uring.

/// E8 Coxeter carrier: `h(E8) = 30`.
pub const E8_COXETER_CARRIER: u64 = 30;

/// Leech kissing carrier.
pub const LEECH_FIELD_CARRIER: u64 = 196_560;

/// E8 no-jam lanes: totatives of 30 and the E8 exponents.
pub const E8_TOTATIVE_STRIDE_LANES: [u64; 8] = [1, 7, 11, 13, 17, 19, 23, 29];

/// Default hotpath lane priority: Leech first, then pilot/toroidal, open
/// construction lanes, antipode, and identity as last resort.
pub const HOTPATH_STRIDE_PRIORITY: [u64; 8] = [11, 7, 19, 13, 17, 23, 29, 1];

/// Hope Jar regime for an exponent-lane stride.
#[derive(Debug, Clone, Copy, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
pub enum HopeJarRegime {
    IdentityBase,
    E8Pilot,
    LeechTurbo,
    OpenConstruction,
    OsiToroidal,
    BoundaryAntipode,
}

impl HopeJarRegime {
    pub const fn wire_name(self) -> &'static str {
        match self {
            HopeJarRegime::IdentityBase => "identity-base",
            HopeJarRegime::E8Pilot => "e8-pilot",
            HopeJarRegime::LeechTurbo => "leech-turbo",
            HopeJarRegime::OpenConstruction => "open-construction",
            HopeJarRegime::OsiToroidal => "osi-toroidal",
            HopeJarRegime::BoundaryAntipode => "boundary-antipode",
        }
    }
}

/// E8 exponent-lane program as Hope Jar regimes.
pub const HOPE_JAR_REGIME_SCHEDULE: [(u64, u64, HopeJarRegime); 8] = [
    (1, 29, HopeJarRegime::IdentityBase),
    (7, 23, HopeJarRegime::E8Pilot),
    (11, 19, HopeJarRegime::LeechTurbo),
    (13, 17, HopeJarRegime::OpenConstruction),
    (17, 13, HopeJarRegime::OpenConstruction),
    (19, 11, HopeJarRegime::OsiToroidal),
    (23, 7, HopeJarRegime::OpenConstruction),
    (29, 1, HopeJarRegime::BoundaryAntipode),
];

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct HotpathStrideRaceLane {
    pub stride: u64,
    pub regime: Option<HopeJarRegime>,
    pub admissible: bool,
    pub penalty_key: u64,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct HotpathStrideRace<const N: usize> {
    pub work_items: u64,
    pub winner: Option<u64>,
    pub lanes: [HotpathStrideRaceLane; N],
}

#[inline]
pub fn gcd(mut a: u64, mut b: u64) -> u64 {
    while b != 0 {
        let next = a % b;
        a = b;
        b = next;
    }
    a
}

#[inline]
pub fn stride_admissible(stride: u64, carrier: u64) -> bool {
    gcd(stride, carrier) == 1
}

pub fn hope_jar_regime(stride: u64) -> Option<HopeJarRegime> {
    HOPE_JAR_REGIME_SCHEDULE
        .iter()
        .find_map(|(candidate, _, regime)| (*candidate == stride).then_some(*regime))
}

#[inline]
pub fn select_hotpath_stride(work_items: u64) -> Option<u64> {
    select_hotpath_stride_from(work_items, &HOTPATH_STRIDE_PRIORITY)
}

pub fn select_hotpath_stride_from(work_items: u64, candidates: &[u64]) -> Option<u64> {
    let mut winner = None;
    let mut winner_penalty = u64::MAX;
    for (priority, stride) in candidates.iter().copied().enumerate() {
        if !stride_admissible(stride, work_items) {
            continue;
        }
        let penalty = hotpath_stride_sort_key(stride, work_items, priority as u64);
        if penalty < winner_penalty || (penalty == winner_penalty && Some(stride) < winner) {
            winner = Some(stride);
            winner_penalty = penalty;
        }
    }
    winner
}

pub fn race_hotpath_strides<const N: usize>(
    work_items: u64,
    candidates: [u64; N],
) -> HotpathStrideRace<N> {
    let mut lanes = [HotpathStrideRaceLane {
        stride: 0,
        regime: None,
        admissible: false,
        penalty_key: u64::MAX,
    }; N];
    let mut winner = None;
    let mut winner_penalty = u64::MAX;
    for (priority, stride) in candidates.into_iter().enumerate() {
        let admissible = stride_admissible(stride, work_items);
        let penalty_key = if admissible {
            hotpath_stride_sort_key(stride, work_items, priority as u64)
        } else {
            u64::MAX
        };
        lanes[priority] = HotpathStrideRaceLane {
            stride,
            regime: hope_jar_regime(stride),
            admissible,
            penalty_key,
        };
        if admissible
            && (penalty_key < winner_penalty
                || (penalty_key == winner_penalty && Some(stride) < winner))
        {
            winner = Some(stride);
            winner_penalty = penalty_key;
        }
    }
    HotpathStrideRace {
        work_items,
        winner,
        lanes,
    }
}

#[inline]
fn hotpath_stride_sort_key(stride: u64, work_items: u64, priority: u64) -> u64 {
    let wrap_skew = work_items % stride;
    priority * 64 + wrap_skew.min(stride - wrap_skew)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn e8_totatives_are_no_jam_lanes() {
        assert_eq!(E8_TOTATIVE_STRIDE_LANES, [1, 7, 11, 13, 17, 19, 23, 29]);
        assert!(E8_TOTATIVE_STRIDE_LANES
            .iter()
            .all(|stride| stride_admissible(*stride, E8_COXETER_CARRIER)));
    }

    #[test]
    fn leech_separates_eleven_from_seven() {
        assert!(stride_admissible(11, LEECH_FIELD_CARRIER));
        assert!(!stride_admissible(7, LEECH_FIELD_CARRIER));
        assert_eq!(hope_jar_regime(11), Some(HopeJarRegime::LeechTurbo));
    }

    #[test]
    fn raced_selection_matches_gnosis_uring_and_aether() {
        assert_eq!(select_hotpath_stride(64), Some(11));
        assert_eq!(select_hotpath_stride(22), Some(7));
        assert_eq!(select_hotpath_stride(77), Some(19));
        assert_eq!(select_hotpath_stride_from(77, &[11, 7]), None);

        let report = race_hotpath_strides(77, HOTPATH_STRIDE_PRIORITY);
        assert_eq!(report.winner, Some(19));
        assert_eq!(report.lanes[0].stride, 11);
        assert!(!report.lanes[0].admissible);
        assert_eq!(report.lanes[0].regime, Some(HopeJarRegime::LeechTurbo));
        assert_eq!(report.lanes[2].stride, 19);
        assert!(report.lanes[2].admissible);
    }
}
